import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Newspaper, Users, FolderOpen, Settings, LogOut, 
  Search, Bell, Grid, X, ArrowRight, Globe, SearchCode, Sparkles, Loader2,
  CheckCircle2, Info, AlertCircle, Clock, Briefcase, Award, Share2, Camera
} from 'lucide-react';
import { AppView, Notification } from '../types';
import { QUICK_TOOLS, MOCK_NEWS, MOCK_EMPLOYEES, MOCK_NOTIFICATIONS } from '../constants';
import { getAIResponse } from '../services/geminiService';

interface NavbarProps {
  currentView: AppView;
  setView: (view: AppView) => void;
  globalSearch: string;
  setGlobalSearch: (search: string) => void;
  onAskAI: (prompt: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ currentView, setView, globalSearch, setGlobalSearch, onAskAI }) => {
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isSearchVisible, setIsSearchVisible] = useState(false);
  const [showSearchPreview, setShowSearchPreview] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>(MOCK_NOTIFICATIONS);

  const [aiPreviewAnswer, setAiPreviewAnswer] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const dropdownRef = useRef<HTMLDivElement>(null);
  const notificationRef = useRef<HTMLDivElement>(null);
  const searchInputRef = useRef<HTMLInputElement>(null);
  const searchPreviewRef = useRef<HTMLDivElement>(null);
  const aiSearchTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const unreadCount = useMemo(() => notifications.filter(n => !n.isRead).length, [notifications]);

  const menuItems = [
    { id: AppView.DASHBOARD, label: '概览', icon: <LayoutDashboard size={18} /> },
    { id: AppView.NEWS, label: '资讯', icon: <Newspaper size={18} /> },
    { id: AppView.DIRECTORY, label: '团队', icon: <Users size={18} /> },
    { id: AppView.TOOLS, label: '工具', icon: <Grid size={18} /> },
  ];

  // AI Debounced lookup
  useEffect(() => {
    if (aiSearchTimeoutRef.current) clearTimeout(aiSearchTimeoutRef.current);

    if (!globalSearch.trim()) {
      setAiPreviewAnswer(null);
      return;
    }

    setIsAiLoading(true);
    aiSearchTimeoutRef.current = setTimeout(async () => {
      const prompt = `作为一个内网助手，请针对以下搜索词提供非常简短（50字以内）的预览回答。如果涉及到特定政策或流程，简要说明：${globalSearch}`;
      const response = await getAIResponse(prompt);
      setAiPreviewAnswer(response);
      setIsAiLoading(false);
    }, 800);

    return () => {
      if (aiSearchTimeoutRef.current) clearTimeout(aiSearchTimeoutRef.current);
    };
  }, [globalSearch]);

  const previewResults = useMemo(() => {
    if (!globalSearch.trim()) return null;
    const s = globalSearch.toLowerCase();
    return {
      tools: QUICK_TOOLS.filter(t => t.name.toLowerCase().includes(s)).slice(0, 3),
      news: MOCK_NEWS.filter(n => n.title.toLowerCase().includes(s)).slice(0, 2),
      employees: MOCK_EMPLOYEES.filter(e => e.name.toLowerCase().includes(s)).slice(0, 3),
    };
  }, [globalSearch]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsProfileOpen(false);
      }
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setIsNotificationsOpen(false);
      }
      if (searchPreviewRef.current && !searchPreviewRef.current.contains(event.target as Node) && !searchInputRef.current?.contains(event.target as Node)) {
        setShowSearchPreview(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (isSearchVisible && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isSearchVisible]);

  const handleViewAllSearch = () => {
    setView(AppView.SEARCH_RESULTS);
    setShowSearchPreview(false);
  };

  const toggleNotificationRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const markAllAsRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
  };

  const getNotificationIcon = (type: Notification['type']) => {
    switch (type) {
      case 'success': return <CheckCircle2 className="text-emerald-500" size={16} />;
      case 'warning': return <AlertCircle className="text-rose-500" size={16} />;
      case 'reminder': return <Clock className="text-amber-500" size={16} />;
      default: return <Info className="text-blue-500" size={16} />;
    }
  };

  return (
    <div className="fixed top-0 left-0 right-0 z-50 flex justify-center px-6 py-2 pointer-events-none">
      <nav className="mica pointer-events-auto h-14 max-w-7xl w-full rounded-full flex items-center px-4 justify-between shadow-[0_8px_30px_-10px_rgba(0,0,0,0.1)] transition-all">
        {/* Brand & Menu */}
        <div className="flex items-center space-x-2 lg:space-x-6 overflow-hidden">
          <div 
            className="flex items-center space-x-3 cursor-pointer group pr-4 border-r border-slate-200/50 dark:border-slate-700/50 shrink-0" 
            onClick={() => setView(AppView.DASHBOARD)}
          >
            <div className="w-8 h-8 lg:w-9 lg:h-9 mesh-gradient rounded-xl flex items-center justify-center text-white font-black text-lg shadow-lg shadow-blue-500/30 group-hover:rotate-12 transition-transform duration-500">
              S
            </div>
            <span className="hidden xl:block font-black text-base text-slate-900 dark:text-white tracking-tighter whitespace-nowrap">ShiKu Home</span>
          </div>

          <div className="flex items-center space-x-1 lg:space-x-2 no-scrollbar">
            {menuItems.map((item) => (
              <button
                key={item.id}
                onClick={() => setView(item.id)}
                className={`relative group flex items-center space-x-2 px-2.5 lg:px-3 py-1.5 rounded-full transition-all duration-500 text-[10px] font-black uppercase tracking-tight whitespace-nowrap ${
                  currentView === item.id 
                    ? 'text-blue-600 dark:text-blue-400 bg-blue-50/50 dark:bg-blue-900/20' 
                    : 'text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-100'
                }`}
              >
                {item.icon && React.isValidElement(item.icon) ? React.cloneElement(item.icon as React.ReactElement<any>, { size: 16 }) : item.icon}
                <span className="hidden sm:block">{item.label}</span>
                {currentView === item.id && (
                  <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-1 h-1 bg-blue-600 rounded-full"></div>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Search & Utilities */}
        <div className="flex items-center space-x-1 lg:space-x-2 ml-2 flex-1 justify-end relative">
          <div className={`transition-all duration-500 flex items-center ${isSearchVisible ? 'flex-1 max-w-xs' : 'w-9'}`}>
            <div className={`relative flex items-center w-full ${!isSearchVisible ? 'justify-center' : ''}`}>
              {isSearchVisible ? (
                <div className="relative w-full animate-in fade-in slide-in-from-right-4 duration-300">
                  <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input
                    ref={searchInputRef}
                    type="text"
                    value={globalSearch}
                    onChange={(e) => {
                      setGlobalSearch(e.target.value);
                      setShowSearchPreview(true);
                    }}
                    onFocus={() => setShowSearchPreview(true)}
                    placeholder="搜索内容..."
                    className="w-full bg-slate-100/70 dark:bg-slate-800/70 border-none rounded-full py-1.5 pl-9 pr-8 text-[11px] font-bold dark:text-white outline-none focus:outline-none transition-all"
                  />
                  <button 
                    onClick={() => { setIsSearchVisible(false); setGlobalSearch(''); setShowSearchPreview(false); }}
                    className="absolute right-1.5 top-1/2 -translate-y-1/2 p-1 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-colors"
                  >
                    <X size={12} className="text-slate-500" />
                  </button>

                  {/* Search Preview */}
                  {showSearchPreview && globalSearch.trim() && (
                    <div 
                      ref={searchPreviewRef}
                      className="absolute top-12 left-0 right-0 bg-white dark:bg-slate-900 rounded-[2rem] shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden flex flex-col z-[60] animate-in fade-in slide-in-from-top-2 duration-300"
                    >
                      <div className="max-h-[70vh] overflow-y-auto p-4 space-y-6">
                        <div className="space-y-3">
                           <h4 className="px-3 text-[9px] font-black uppercase tracking-widest text-blue-500 flex items-center">
                             <Sparkles size={10} className="mr-1.5" />
                             AI 智能建议
                           </h4>
                           <div className="relative mica border-blue-100 dark:border-blue-900/50 rounded-2xl p-4 bg-blue-50/20 dark:bg-blue-900/10 overflow-hidden">
                             {isAiLoading ? (
                               <div className="flex items-center space-x-3 py-2 text-slate-400">
                                 <Loader2 size={16} className="animate-spin" />
                                 <span className="text-[11px] font-bold">正在思考您的需求...</span>
                               </div>
                             ) : aiPreviewAnswer ? (
                               <div className="space-y-3 animate-in fade-in duration-500">
                                 <p className="text-[11px] text-slate-700 dark:text-slate-300 font-medium leading-relaxed italic">
                                   "{aiPreviewAnswer}"
                                 </p>
                                 <button 
                                   onClick={() => { onAskAI(globalSearch); setShowSearchPreview(false); }}
                                   className="flex items-center space-x-2 text-[10px] font-black uppercase tracking-widest text-blue-600 hover:text-blue-700 transition-colors"
                                 >
                                   <span>与 AI 继续对话</span>
                                   <ArrowRight size={12} />
                                 </button>
                               </div>
                             ) : (
                               <button 
                                 onClick={() => { onAskAI(globalSearch); setShowSearchPreview(false); }}
                                 className="w-full text-left flex items-center justify-between group"
                               >
                                 <span className="text-[11px] font-bold text-slate-500 italic">点击让 AI 深度解析您的提问...</span>
                                 <Sparkles size={14} className="text-blue-400 group-hover:scale-125 transition-transform" />
                               </button>
                             )}
                           </div>
                        </div>

                        {previewResults?.tools.length! > 0 && (
                          <div className="space-y-2">
                            <h4 className="px-3 text-[9px] font-black uppercase tracking-widest text-slate-400">应用与工具</h4>
                            <div className="grid grid-cols-1 gap-1">
                              {previewResults?.tools.map(tool => (
                                <button key={tool.id} className="w-full flex items-center space-x-3 p-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-2xl transition-colors text-left group">
                                  <div className={`w-8 h-8 ${tool.color} rounded-lg flex items-center justify-center`}>
                                     {React.isValidElement(tool.icon) ? React.cloneElement(tool.icon as React.ReactElement<any>, { size: 14 }) : tool.icon}
                                  </div>
                                  <span className="text-xs font-bold text-slate-700 dark:text-slate-200">{tool.name}</span>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}

                        {previewResults?.employees.length! > 0 && (
                          <div className="space-y-2">
                            <h4 className="px-3 text-[9px] font-black uppercase tracking-widest text-slate-400">团队成员</h4>
                            <div className="grid grid-cols-1 gap-1">
                              {previewResults?.employees.map(emp => (
                                <button key={emp.id} className="w-full flex items-center space-x-3 p-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-2xl transition-colors text-left group">
