              </div>
              <div className="px-4 py-2 bg-purple-500 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-purple-500/20">
                超级管理员模式
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
              {[
                { label: '昨日访问 (PV)', val: '4,281', change: '+12%', icon: <TrendingUp size={18} />, color: 'blue' },
                { label: '活跃用户', val: '852', change: '+5%', icon: <User size={18} />, color: 'indigo' },
                { label: '系统负载', val: '24%', change: '稳定', icon: <Monitor size={18} />, color: 'emerald' },
                { label: 'AI 处理量', val: '1,293', change: '+45%', icon: <Zap size={18} />, color: 'amber' }
              ].map((stat, i) => (
                <div key={i} className="mica p-5 rounded-[2rem] border border-white/50">
                  <div className={`w-10 h-10 bg-${stat.color}-500/10 text-${stat.color}-600 rounded-xl flex items-center justify-center mb-4`}>
                    {stat.icon}
                  </div>
                  <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">{stat.label}</p>
                  <div className="flex items-baseline justify-between">
                    <h3 className="text-2xl font-black text-slate-900 dark:text-white">{stat.val}</h3>
                    <span className="text-[10px] font-bold text-emerald-500">{stat.change}</span>
                  </div>
                </div>
              ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className="lg:col-span-8 space-y-6">
                 <div className="mica rounded-[2.5rem] overflow-hidden">
                    <div className="px-8 py-6 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center">
                      <h3 className="text-sm font-black uppercase tracking-widest text-slate-800 dark:text-white">待处理申请</h3>
                    </div>
                    <div className="p-8 text-center">
                      <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
