                      <p className="text-sm font-black text-slate-400 uppercase tracking-widest">目前暂无待审事项</p>
                    </div>
                 </div>
              </div>
              <div className="lg:col-span-4 space-y-6">
                 <div className="mica p-6 rounded-[2.5rem]">
                    <h3 className="text-sm font-black uppercase tracking-widest text-slate-800 dark:text-white mb-6">快捷操作</h3>
                    <div className="space-y-3">
                       {[
                         { label: '发布全员通知', icon: <Zap size={16} />, color: 'bg-blue-600' },
                         { label: '编辑导航链接', icon: <LayoutGrid size={16} />, color: 'bg-purple-600' },
                         { label: '清理缓存', icon: <Trash2 size={16} />, color: 'bg-rose-600' },
                       ].map((act, i) => (
                         <button key={i} className="w-full flex items-center justify-between p-4 rounded-3xl bg-slate-50 dark:bg-slate-800/50 hover:bg-white dark:hover:bg-slate-800 transition-all group">
