                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Product Design Lead</p>
                  </div>

                  {isAdmin && (
                    <button 
                      onClick={() => { setView(AppView.ADMIN); setIsProfileOpen(false); }}
