    port: '389',
    baseDn: 'dc=shiku,dc=com',
    bindDn: 'cn=admin,dc=shiku,dc=com',
    password: '••••••••••••',
    syncInterval: 'daily'
  });
  const [isLdapTesting, setIsLdapTesting] = useState(false);
