interface AIAssistantProps {
  isOpen: boolean;
  setIsOpen: (open: boolean) => void;
  initialPrompt?: string;
  currentView?: AppView;
}

interface Message {
  role: 'user' | 'ai';
  text: string;
  isStreaming?: boolean;
  timestamp: string;
}

const SUGGESTED_PROMPTS = [
  "如何申请年假？",
  "IT 部门的联系方式是什么？",
  "公司最新的差旅报销政策",
  "怎么预定5号会议室？"
];

const AIAssistant: React.FC<AIAssistantProps> = ({ isOpen, setIsOpen, initialPrompt, currentView }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { 
      role: 'ai', 
      text: "你好！我是 ShiKu Assistant。我已经准备好在 **ShiKu Home** 协助你的日常工作了。有什么可以帮你的吗？",
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [copiedId, setCopiedId] = useState<number | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isOpen, isLoading]);

  // Focus input on open
  useEffect(() => {
    if (isOpen && inputRef.current && !isLoading) {
      setTimeout(() => inputRef.current?.focus(), 400);
    }
  }, [isOpen]);

  const handleSend = useCallback(async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMsg = text.trim();
    const timestamp = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    setInput('');
    setIsLoading(true);

    // Add user message
    setMessages(prev => [...prev, { role: 'user', text: userMsg, timestamp }]);

    // Add placeholder for AI response
    setMessages(prev => [...prev, { role: 'ai', text: '', isStreaming: true, timestamp }]);

    let fullResponse = '';
    const viewContext = currentView ? `用户当前正在查看: ${currentView}` : undefined;

    await streamAIResponse(
      userMsg, 
      (chunk) => {
        fullResponse += chunk;
        setMessages(prev => {
          const newMessages = [...prev];
          const lastMsg = newMessages[newMessages.length - 1];
          if (lastMsg.role === 'ai') {
            lastMsg.text = fullResponse;
          }
          return newMessages;
        });
      },
      () => {
        setIsLoading(false);
        setMessages(prev => {
          const newMessages = [...prev];
          const lastMsg = newMessages[newMessages.length - 1];
          lastMsg.isStreaming = false;
          return newMessages;
        });
      },
      viewContext
    );
  }, [isLoading, currentView]);

  // Handle deep-linked prompt
  useEffect(() => {
    if (isOpen && initialPrompt) {
      handleSend(initialPrompt);
    }
  }, [isOpen, initialPrompt]);

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedId(index);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const clearChat = () => {
    if (confirm('确定要清空所有对话记录吗？')) {
      setMessages([{ 
        role: 'ai', 
        text: "对话已重置。有什么新问题吗？",
