                               <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                             </div>
                           )}
                         </div>
                      ) : (
                        <p className="font-medium">{m.text}</p>
